import React, { useState } from 'react';
import axios from 'axios';
import './App.css';

function App() {
  const [pdfUrls, setPdfUrls] = useState('');
  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState('');
  const [error, setError] = useState('');
  const [result, setResult] = useState(null);
  const [extractedData, setExtractedData] = useState(null);

  const API_BASE = 'http://localhost:5001/api/ipqc-ocr';

  const handleProcessOCR = async () => {
    if (!pdfUrls.trim()) {
      setError('Please enter PDF URLs (one per line)');
      return;
    }

    setLoading(true);
    setStatus('Processing PDF files with Azure Document Intelligence...');
    setError('');
    setResult(null);
    setExtractedData(null);

    try {
      const urls = pdfUrls.split('\n').map(url => url.trim()).filter(url => url);
      
      setStatus(`Processing ${urls.length} PDF file(s)...`);

      const response = await axios.post(`${API_BASE}/process-from-urls`, {
        pdfUrls: urls
      });

      if (response.data.success) {
        setResult(response.data);
        setExtractedData(response.data.extractedData);
        setStatus('✅ OCR Complete! Excel file ready for download.');
      } else {
        setError(response.data.error || 'OCR processing failed');
        setStatus('');
      }
    } catch (err) {
      setError(err.response?.data?.error || err.message || 'Failed to process OCR');
      setStatus('');
    } finally {
      setLoading(false);
    }
  };

  const handleDownloadExcel = () => {
    if (result && result.outputFile) {
      window.open(`${API_BASE}/download/${result.outputFile}`, '_blank');
    }
  };

  const sampleUrls = `https://example.com/page1.pdf
https://example.com/page2.pdf
https://example.com/page3.pdf`;

  return (
    <div className="app-container">
      <div className="header">
        <h1>📄 IPQC OCR System</h1>
        <p>Extract data from PDF documents and fill Excel automatically</p>
      </div>

      <div className="main-card">
        <div className="input-section">
          <label htmlFor="pdfUrls">
            <span className="label-icon">🔗</span>
            Enter PDF URLs (one per line):
          </label>
          <textarea
            id="pdfUrls"
            value={pdfUrls}
            onChange={(e) => setPdfUrls(e.target.value)}
            placeholder={sampleUrls}
            rows={6}
            disabled={loading}
          />
        </div>

        <div className="button-section">
          <button
            onClick={handleProcessOCR}
            disabled={loading || !pdfUrls.trim()}
            className="process-btn"
          >
            {loading ? (
              <>
                <span className="spinner"></span>
                Processing...
              </>
            ) : (
              <>
                <span>🚀</span>
                Process OCR
              </>
            )}
          </button>

          {result && (
            <button onClick={handleDownloadExcel} className="download-btn">
              <span>📥</span>
              Download Excel
            </button>
          )}
        </div>

        {status && (
          <div className="status-message">
            {status}
          </div>
        )}

        {error && (
          <div className="error-message">
            ❌ {error}
          </div>
        )}

        {extractedData && (
          <div className="extracted-data">
            <h3>📋 Extracted Data Preview</h3>
            <div className="data-grid">
              {extractedData.date && (
                <div className="data-item">
                  <span className="label">Date:</span>
                  <span className="value">{extractedData.date}</span>
                </div>
              )}
              {extractedData.lotNumber && (
                <div className="data-item">
                  <span className="label">Lot Number:</span>
                  <span className="value">{extractedData.lotNumber}</span>
                </div>
              )}
              {extractedData.type && (
                <div className="data-item">
                  <span className="label">Type:</span>
                  <span className="value">{extractedData.type}</span>
                </div>
              )}
              {extractedData.cell && (
                <div className="data-item">
                  <span className="label">Cell:</span>
                  <span className="value">{extractedData.cell}</span>
                </div>
              )}
              {extractedData.frameSize && (
                <div className="data-item">
                  <span className="label">Frame Size:</span>
                  <span className="value">{extractedData.frameSize}</span>
                </div>
              )}
              {extractedData.glass && (
                <div className="data-item">
                  <span className="label">Glass:</span>
                  <span className="value">{extractedData.glass}</span>
                </div>
              )}
              {extractedData.backsheet && (
                <div className="data-item">
                  <span className="label">Backsheet:</span>
                  <span className="value">{extractedData.backsheet}</span>
                </div>
              )}
              {extractedData.humidity && (
                <div className="data-item">
                  <span className="label">Humidity:</span>
                  <span className="value">{extractedData.humidity}%</span>
                </div>
              )}
              {extractedData.anodizing && (
                <div className="data-item">
                  <span className="label">Anodizing:</span>
                  <span className="value">{extractedData.anodizing}</span>
                </div>
              )}
              {extractedData.glueWeightShort && (
                <div className="data-item">
                  <span className="label">Glue (Short):</span>
                  <span className="value">{extractedData.glueWeightShort}</span>
                </div>
              )}
              {extractedData.glueWeightLong && (
                <div className="data-item">
                  <span className="label">Glue (Long):</span>
                  <span className="value">{extractedData.glueWeightLong}</span>
                </div>
              )}
            </div>

            {extractedData.serialNumbers && extractedData.serialNumbers.length > 0 && (
              <div className="serial-section">
                <h4>Serial Numbers ({extractedData.serialNumbers.length})</h4>
                <div className="serial-grid">
                  {extractedData.serialNumbers.slice(0, 20).map((serial, idx) => (
                    <span key={idx} className="serial-item">{serial}</span>
                  ))}
                  {extractedData.serialNumbers.length > 20 && (
                    <span className="serial-item more">+{extractedData.serialNumbers.length - 20} more</span>
                  )}
                </div>
              </div>
            )}
          </div>
        )}
      </div>

      <div className="footer">
        <p>IPQC OCR System v1.0 | Powered by Azure Document Intelligence</p>
      </div>
    </div>
  );
}

export default App;
